const body = $input.first().json.body || $input.first().json;
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!uuidRegex.test(body.tenantId)) {
  throw new Error('Invalid tenantId format');
}

const profils = ['MINIMUM', 'BASIC', 'EN16931'];
const statuts = ['generee', 'transmise', 'acceptee', 'refusee'];

return [{ json: {
  tenantId: body.tenantId,
  profil: body.profil || null,
  statut: body.statut || null,
  page: body.page || 1,
  limit: body.limit || 50
} }];

var countResult = $('05. Count').first();
var total = countResult && countResult.json ? parseInt(countResult.json.total || '0', 10) : 0;
var listItems = $input.all();
var data = listItems.map(function(item) { return item.json; }).filter(function(r) { return r && r.id; });

return [{
  json: {
    success: true,
    total: total,
    count: data.length,
    data: data
  }
}];
